import axios from "axios";
import httpStatus from "http-status";
import { createContext, useState } from "react";
import { useNavigate } from "react-router-dom";
import server from "../environment";

export const AdminAuthContext = createContext({});

const usersClient = axios.create({
  baseURL: `${server}/api/v1/users`,
});

const meetingsClient = axios.create({
  baseURL: `${server}/api/v1/meetings`,
});

const attachToken = (config) => {
  const token = localStorage.getItem("admin_token");
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
};

usersClient.interceptors.request.use(attachToken);
meetingsClient.interceptors.request.use(attachToken);

export const AdminAuthProvider = ({ children }) => {
  const navigate = useNavigate();
  const [adminUser, setAdminUser] = useState(() => {
    const raw = localStorage.getItem("admin_user");
    if (!raw) return null;
    try {
      return JSON.parse(raw);
    } catch {
      return null;
    }
  });

  const loginAdmin = async ({ username, email, password }) => {
    const response = await usersClient.post("/login", { username, email, password });
    if (response.status !== httpStatus.OK) {
      throw new Error("Unable to login");
    }

    localStorage.setItem("admin_token", response.data.token);
    localStorage.setItem("admin_user", JSON.stringify(response.data.user));
    setAdminUser(response.data.user);
    navigate("/dashboard");
  };

  const logoutAdmin = async () => {
    try {
      await usersClient.post("/logout");
    } catch {
      // no-op
    }

    localStorage.removeItem("admin_token");
    localStorage.removeItem("admin_user");
    setAdminUser(null);
    navigate("/login");
  };

  const getScheduledMeetings = async () => {
    const response = await meetingsClient.get("/host/scheduled");
    return response.data;
  };

  const getMeetingHistory = async () => {
    const response = await usersClient.get("/activity");
    return response.data;
  };

  const getRecordings = async (meetingId, query = {}) => {
    const response = await meetingsClient.get(`/${meetingId}/recordings`, {
      params: query,
    });
    return response.data;
  };

  const value = {
    adminUser,
    loginAdmin,
    logoutAdmin,
    getScheduledMeetings,
    getMeetingHistory,
    getRecordings,
  };

  return <AdminAuthContext.Provider value={value}>{children}</AdminAuthContext.Provider>;
};
